import { useApp } from '../context/AppContext';
import Button from '../components/Button';

export default function BookingsPage() {
  const { state, dispatch } = useApp();
  const { bookings } = state;

  if (bookings.length === 0) {
    return (
      <div className="page-wrap">
        <div className="page-header">
          <h1>My Bookings</h1>
        </div>
        <div className="empty-state">
          <div className="icon">🛎️</div>
          <h3>No bookings yet</h3>
          <p>Explore our rooms and make your first reservation</p>
          <Button
            variant="primary"
            onClick={() => dispatch({ type: 'SET_PAGE', payload: 'dashboard' })}
          >
            Browse Rooms
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="page-wrap">
      <div className="page-header">
        <h1>My Bookings</h1>
        <p>
          {bookings.length} reservation{bookings.length > 1 ? 's' : ''}
        </p>
      </div>

      <div style={styles.list}>
        {bookings.map((b) => (
          <div key={b.id} style={styles.card}>
            <div style={styles.icon}>{b.roomImage}</div>
            <div style={styles.info}>
              <h4 style={styles.roomName}>{b.roomName}</h4>
              <p style={styles.meta}>{b.roomType}</p>
              <p style={styles.dates}>
                📅 {b.checkIn} → {b.checkOut}
              </p>
              <p style={styles.bookedAt}>Booked on {b.bookedAt}</p>
              <span className="status-badge status-confirmed">Confirmed</span>
            </div>
            <div style={styles.priceCol}>
              <div style={styles.price}>₹{b.total.toLocaleString()}</div>
              <div style={styles.nights}>
                {b.nights} night{b.nights > 1 ? 's' : ''}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

const styles = {
  list: { display: 'flex', flexDirection: 'column', gap: 16 },
  card: {
    background: 'var(--surface)',
    border: '1px solid var(--border)',
    borderRadius: 8,
    padding: 24,
    display: 'grid',
    gridTemplateColumns: '64px 1fr auto',
    gap: 24,
    alignItems: 'center',
  },
  icon: {
    width: 64,
    height: 64,
    background: 'var(--warm)',
    borderRadius: 'var(--radius)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: 32,
  },
  info: {},
  roomName: {
    fontFamily: "'Cormorant Garamond', serif",
    fontSize: 22,
    fontWeight: 400,
    marginBottom: 4,
  },
  meta: { fontSize: 13, color: 'var(--muted)', marginBottom: 4 },
  dates: { fontSize: 13, color: 'var(--ink)', marginBottom: 2 },
  bookedAt: { fontSize: 12, color: 'var(--muted)', marginBottom: 4 },
  priceCol: { textAlign: 'right' },
  price: {
    fontFamily: "'Cormorant Garamond', serif",
    fontSize: 26,
    fontWeight: 600,
  },
  nights: { fontSize: 12, color: 'var(--muted)', marginTop: 4 },
};
